final class DebayerRCDTests: XCTestCase {

    // MARK: Helpers

    private func makeImage(pixels: [Float], w: Int, h: Int) -> AstroImage {
        AstroImage(width: w, height: h, channels: 1, pixels: pixels, sourceIsLinear: true)
    }

    private func assertGolden(cfa cfaPx: [Float], expected: [Float],
                               pattern: BayerPattern, label: String) {
        let img = makeImage(pixels: cfaPx, w: goldenW, h: goldenH)
        let out = Debayer.rcd(cfa: img, pattern: pattern)
        XCTAssertEqual(out.pixels.count, expected.count, "\(label): output size mismatch")
        let tol: Float = 1e-4
        var maxErr: Float = 0
        for i in 0..<min(out.pixels.count, expected.count) {
            let err = abs(out.pixels[i] - expected[i])
            if err > maxErr { maxErr = err }
            XCTAssertLessThanOrEqual(err, tol,
                "\(label): pixel \(i) got \(out.pixels[i]) expected \(expected[i]) diff \(err)")
        }
        // print for CI logs
        _ = maxErr
    }

    // MARK: Golden vector tests (1e-4 tolerance)

    func testGoldenVectorGRBG() {
        assertGolden(cfa: cfa_GRBG, expected: expected_GRBG, pattern: .grbg, label: "GRBG")
    }
    func testGoldenVectorRGGB() {
        assertGolden(cfa: cfa_RGGB, expected: expected_RGGB, pattern: .rggb, label: "RGGB")
    }
    func testGoldenVectorBGGR() {
        assertGolden(cfa: cfa_BGGR, expected: expected_BGGR, pattern: .bggr, label: "BGGR")
    }
    func testGoldenVectorGBRG() {
        assertGolden(cfa: cfa_GBRG, expected: expected_GBRG, pattern: .gbrg, label: "GBRG")
    }

    // MARK: Flat field — constant CFA

    func testFlatFieldExactEverywhere() {
        let value: Float = 0.37
        let w = 32, h = 32, plane = w * h
        let cfaPx = [Float](repeating: value, count: w * h)
        for pat in [BayerPattern.grbg, .rggb, .bggr, .gbrg] {
            let img = AstroImage(width: w, height: h, channels: 1, pixels: cfaPx, sourceIsLinear: true)
            let out = Debayer.rcd(cfa: img, pattern: pat)
            XCTAssertEqual(out.pixels.count, plane * 3, "flat-field \(pat.rawValue): size")
            for i in 0..<out.pixels.count {
                // 1e-5 tolerance: EPS=1e-5 in the ratio correction causes ~1.25e-6 deviation
                // even in float64; float32 accumulation keeps errors well under 1e-4.
                XCTAssertEqual(out.pixels[i], value, accuracy: 1e-4,
                    "flat-field \(pat.rawValue): pixel \(i) = \(out.pixels[i])")
            }
        }
    }

    // MARK: Parallel == serial (byte-identical)

    func testParallelEqualsSerial() {
        let w = 128, h = 128
        var px = [Float](repeating: 0, count: w * h)
        for i in 0..<px.count { px[i] = Float((i * 17 + 7) % 251) / 251.0 }
        let img = AstroImage(width: w, height: h, channels: 1, pixels: px, sourceIsLinear: true)
        let serial   = Debayer.rcd(cfa: img, pattern: .rggb, minRows: .max)
        let parallel = Debayer.rcd(cfa: img, pattern: .rggb, minRows: 1)
        XCTAssertEqual(serial.pixels, parallel.pixels, "RCD serial vs parallel must be byte-identical")
    }

    // MARK: Tiny frame falls back to bilinear

    func testTinyFrameFallsBackToBilinear() {
        let w = 6, h = 6
        var px = [Float](repeating: 0, count: w * h)
        for i in 0..<px.count { px[i] = Float(i) / Float(w * h) }
        let img = AstroImage(width: w, height: h, channels: 1, pixels: px, sourceIsLinear: true)
        let rcd = Debayer.rcd(cfa: img, pattern: .grbg)
        let bil = Debayer.bilinear(cfa: img, pattern: .grbg)
        XCTAssertEqual(rcd.pixels, bil.pixels, "tiny frame: rcd must equal bilinear byte-for-byte")
    }

    // MARK: Output finite and clamped

    func testOutputFiniteAndClamped() {
        let w = 128, h = 128
        var px = [Float](repeating: 0, count: w * h)
        for i in 0..<px.count {
            // mix of 0, 1, and intermediate values
            let v = Float((i * 13 + 3) % 256) / 255.0
            px[i] = v
        }
        // force a few 0s and 1s
        px[0] = 0; px[1] = 1; px[w] = 0; px[w+1] = 1
        let img = AstroImage(width: w, height: h, channels: 1, pixels: px, sourceIsLinear: true)
        let out = Debayer.rcd(cfa: img, pattern: BayerPattern.grbg)
        for (i, v) in out.pixels.enumerated() {
            XCTAssertTrue(v.isFinite, "pixel \(i) is not finite: \(v)")
            XCTAssertGreaterThanOrEqual(v, 0.0, "pixel \(i) below 0: \(v)")
            XCTAssertLessThanOrEqual(v, 1.0, "pixel \(i) above 1: \(v)")
        }
    }

    // MARK: Star sharper than bilinear

    func testStarSharperThanBilinear() {
        // Synthesize a 64×64 truth: flat sky 0.05 + one Gaussian star at center
        let w = 64, h = 64
        let starY = 32.0, starX = 32.0
        let sigma = 1.2, amp = 0.8, sky: Float = 0.05
        var truth = [[Float]](repeating: [Float](repeating: 0, count: w), count: h)
        for y in 0..<h { for x in 0..<w {
            let dy = Double(y) - starY, dx = Double(x) - starX
            let g = Float(amp * exp(-(dy*dy + dx*dx) / (2*sigma*sigma)))
            truth[y][x] = min(1, sky + g)
        }}

        // Mosaic per GRBG: CFA[y][x] = truth[y][x] on the channel at that site
        let pattern = BayerPattern.grbg
        var cfaPx = [Float](repeating: 0, count: w * h)
        for y in 0..<h { for x in 0..<w {
            let ch = pattern.channel(row: y, col: x)
            // truth is achromatic (all channels equal)
            cfaPx[y*w+x] = truth[y][x]
        }}
        let img = AstroImage(width: w, height: h, channels: 1, pixels: cfaPx, sourceIsLinear: true)
        let rcdOut = Debayer.rcd(cfa: img, pattern: pattern)
        let bilOut = Debayer.bilinear(cfa: img, pattern: pattern)
        let plane = w * h

        // Compute MSE over 5×5 core centered on the star for the luminance (green) channel
        let cy = Int(starY), cx = Int(starX)
        var mseRCD: Float = 0, mseBil: Float = 0
        var count = 0
        for dy in -2...2 { for dx in -2...2 {
            let y = cy + dy, x = cx + dx
            guard y >= 0, y < h, x >= 0, x < w else { continue }
            let t = truth[y][x]
            let i = y*w+x
            // Use green channel (index 1) as luminance
            let errR: Float = rcdOut.pixels[plane + i] - t
            let errB: Float = bilOut.pixels[plane + i] - t
            mseRCD += errR * errR
            mseBil += errB * errB
            count += 1
        }}
        mseRCD /= Float(count)
        mseBil /= Float(count)
        XCTAssertLessThan(mseRCD, mseBil,
            "RCD (MSE=\(mseRCD)) should be sharper than bilinear (MSE=\(mseBil)) on star core")
    }
}

